    "types": ["node"],
    "files": ["types/multer.d.ts"]
  },
  "include": ["src/**/*"],
  "exclude": ["node_modules"]
}
```

With this setup, the `multer` property will be added to the `Request` interface in the Express namespace. You can then access the uploaded file using `req.file` within your route handlers without any TypeScript errors.

